{
  "name": "Orchestra Score Gateway",
  "description": "A secure access management system for orchestra members to view scores during rehearsal times or via temporary administrative grants.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Instrument = 'Violin' | 'Viola' | 'Cello' | 'Double Bass' | 'Flute' | 'Oboe' | 'Clarinet' | 'Bassoon' | 'Horn' | 'Trumpet' | 'Trombone' | 'Tuba' | 'Percussion' | 'Piano';

export interface User {
  id: string;
  name: string;
  instrument: Instrument;
  role: 'member' | 'admin';
  temp_access_until: string | null; // ISO string
}

export interface Score {
  instrument: Instrument;
  notion_url: string;
}

export interface AuthState {
  user: User | null;
  isAuthenticated: boolean;
}

import { User, Score, Instrument } from './types';

// Initial Mock Data
const INITIAL_USERS: User[] = [
  { id: 'admin', name: 'Admin User', instrument: 'Piano', role: 'admin', temp_access_until: null },
  { id: 'violin1', name: 'Kim Violin', instrument: 'Violin', role: 'member', temp_access_until: null },
  { id: 'cello1', name: 'Lee Cello', instrument: 'Cello', role: 'member', temp_access_until: null },
];

const SCORES: Score[] = [
  { instrument: 'Violin', notion_url: 'https://notion.so/orchestra/violin-scores-example' },
  { instrument: 'Cello', notion_url: 'https://notion.so/orchestra/cello-scores-example' },
  { instrument: 'Piano', notion_url: 'https://notion.so/orchestra/piano-scores-example' },
];

// Simple persistence in LocalStorage for demonstration
const DB_KEY = 'orchestra_gateway_db';

export const getStoredUsers = (): User[] => {
  const stored = localStorage.getItem(DB_KEY);
  return stored ? JSON.parse(stored) : INITIAL_USERS;
};

export const saveUsers = (users: User[]) => {
  localStorage.setItem(DB_KEY, JSON.stringify(users));
};

export const getScoreForInstrument = (instrument: Instrument): string => {
  const score = SCORES.find(s => s.instrument === instrument);
  return score ? score.notion_url : 'https://notion.so/orchestra/general-info';
};

export const isAccessAllowed = (user: User): { allowed: boolean; reason?: string } => {
  const now = new Date();

  // 1. Regular Time Check: Tuesday 18:00 ~ 23:00
  const isTuesday = now.getDay() === 2;
  const hour = now.getHours();
  if (isTuesday && hour >= 18 && hour < 23) {
    return { allowed: true, reason: 'Regular Rehearsal Time' };
  }

  // 2. Temporary Access Check
  if (user.temp_access_until) {
    const expiry = new Date(user.temp_access_until);
    if (now < expiry) {
      return { allowed: true, reason: `Temporary Access Granted (until ${expiry.toLocaleTimeString()})` };
    }
  }

  // 3. Admin Always Access
  if (user.role === 'admin') {
    return { allowed: true, reason: 'Administrator Access' };
  }

  return { allowed: false, reason: 'Outside of rehearsal hours or missing temporary permission.' };
};

import React, { useState, useEffect } from 'react';
import { User, AuthState } from './types';
import { getStoredUsers, saveUsers, isAccessAllowed, getScoreForInstrument } from './db';
import LoginPage from './components/LoginPage';
import MemberDashboard from './components/MemberDashboard';
import AdminDashboard from './components/AdminDashboard';
import { Lock, Music, ShieldCheck, LogOut } from 'lucide-react';

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({ user: null, isAuthenticated: false });
  const [currentPage, setCurrentPage] = useState<'home' | 'scores' | 'admin'>('home');

  // Load session from local storage on mount
  useEffect(() => {
    const savedSession = localStorage.getItem('orchestra_session');
    if (savedSession) {
      setAuth({ user: JSON.parse(savedSession), isAuthenticated: true });
    }
  }, []);

  const handleLogin = (userId: string, pass: string) => {
    // In a real Flask app, this would be a POST request
    const users = getStoredUsers();
    const user = users.find(u => u.id === userId);

    // For mock, any password that matches "1234" or matches userId works
    if (user && (pass === '1234' || pass === userId)) {
      setAuth({ user, isAuthenticated: true });
      localStorage.setItem('orchestra_session', JSON.stringify(user));
    } else {
      alert('Invalid credentials. (Try ID: admin/violin1/cello1 and PW: 1234)');
    }
  };

  const handleLogout = () => {
    setAuth({ user: null, isAuthenticated: false });
    localStorage.removeItem('orchestra_session');
    setCurrentPage('home');
  };

  const extendAccess = (userId: string) => {
    const users = getStoredUsers();
    const updatedUsers = users.map(u => {
      if (u.id === userId) {
        const currentUntil = u.temp_access_until ? new Date(u.temp_access_until) : new Date();
        const base = currentUntil > new Date() ? currentUntil : new Date();
        const newUntil = new Date(base.getTime() + 60 * 60 * 1000); // +1 hour
        return { ...u, temp_access_until: newUntil.toISOString() };
      }
      return u;
    });
    saveUsers(updatedUsers);

    // Update local state if the current user was modified
    if (auth.user?.id === userId) {
      const updatedUser = updatedUsers.find(u => u.id === userId)!;
      setAuth(prev => ({ ...prev, user: updatedUser }));
      localStorage.setItem('orchestra_session', JSON.stringify(updatedUser));
    }

    alert(`Access extended for 1 hour for ${userId}`);
  };

  if (!auth.isAuthenticated || !auth.user) {
    return <LoginPage onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Navigation Header */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between sticky top-0 z-10 shadow-sm">
        <div className="flex items-center gap-2">
          <Music className="text-indigo-600 w-8 h-8" />
          <h1 className="text-xl font-bold text-slate-800 hidden sm:block">Score Gateway</h1>
        </div>

        <nav className="flex items-center gap-4">
          <button 
            onClick={() => setCurrentPage('home')}
            className={`px-3 py-2 rounded-md transition ${currentPage === 'home' ? 'bg-indigo-50 text-indigo-700' : 'text-slate-600 hover:bg-slate-100'}`}
          >
            Dashboard
          </button>

          {auth.user.role === 'admin' && (
            <button 
              onClick={() => setCurrentPage('admin')}
              className={`px-3 py-2 rounded-md flex items-center gap-2 transition ${currentPage === 'admin' ? 'bg-indigo-50 text-indigo-700' : 'text-slate-600 hover:bg-slate-100'}`}
            >
              <ShieldCheck size={18} />
              Admin
            </button>
          )}

          <div className="h-6 w-px bg-slate-200 mx-2"></div>

          <div className="flex items-center gap-3">
            <span className="text-sm font-medium text-slate-700 hidden md:block">
              {auth.user.name} ({auth.user.instrument})
            </span>
            <button 
              onClick={handleLogout}
              className="p-2 text-slate-500 hover:text-red-600 hover:bg-red-50 rounded-full transition"
              title="Logout"
            >
              <LogOut size={20} />
            </button>
          </div>
        </nav>
      </header>

      <main className="flex-1 container mx-auto px-4 py-8 max-w-4xl">
        {currentPage === 'home' && (
          <MemberDashboard 
            user={auth.user} 
            onOpenScores={() => setCurrentPage('scores')} 
          />
        )}

        {currentPage === 'scores' && (
          <ScoreViewer user={auth.user} />
        )}

        {currentPage === 'admin' && auth.user.role === 'admin' && (
          <AdminDashboard onExtendAccess={extendAccess} />
        )}
      </main>

      <footer className="py-6 text-center text-slate-400 text-sm border-t border-slate-100">
        &copy; 2024 Orchestra Digital Library System
      </footer>
    </div>
  );
};

// Internal Helper for Score Logic
const ScoreViewer: React.FC<{ user: User }> = ({ user }) => {
  const { allowed, reason } = isAccessAllowed(user);

  if (!allowed) {
    return (
      <div className="bg-white rounded-2xl shadow-xl p-8 text-center max-w-md mx-auto border border-red-100">
        <div className="bg-red-50 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-6">
          <Lock className="text-red-500 w-8 h-8" />
        </div>
        <h2 className="text-2xl font-bold text-slate-800 mb-2">Access Denied</h2>
        <p className="text-slate-600 mb-6">
          {reason}
        </p>
        <div className="bg-slate-50 p-4 rounded-lg text-left text-sm text-slate-500">
          <p className="font-semibold mb-1">Standard Rehearsal Hours:</p>
          <p>Every Tuesday 18:00 - 23:00</p>
        </div>
      </div>
    );
  }

  const notionUrl = getScoreForInstrument(user.instrument);

  return (
    <div className="bg-white rounded-2xl shadow-xl p-8 border border-green-100 text-center">
      <div className="bg-green-50 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-6">
        <ShieldCheck className="text-green-500 w-8 h-8" />
      </div>
      <h2 className="text-2xl font-bold text-slate-800 mb-2">Access Granted</h2>
      <p className="text-slate-600 mb-8 italic">
        "Music is the shorthand of emotion."
      </p>

      <div className="bg-indigo-50 border border-indigo-100 rounded-xl p-6 mb-8 text-left">
        <h3 className="font-semibold text-indigo-900 mb-2">Instrument Sheet Music: {user.instrument}</h3>
        <p className="text-indigo-700 text-sm mb-4">
          The link below redirects you to the secure Notion repository. 
          Please do not share this URL with outsiders.
        </p>

        <a 
          href={notionUrl}
          target="_blank" 
          rel="noopener noreferrer"
          className="block w-full text-center bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 px-6 rounded-lg transition transform hover:scale-[1.02]"
        >
          Open Score in Notion
        </a>
      </div>

      <p className="text-xs text-slate-400">
        Session Status: {reason}
      </p>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Music, Lock, User as UserIcon } from 'lucide-react';

