};

export default LoginPage;

import React, { useState, useEffect } from 'react';
import { User } from '../types';
import { getStoredUsers } from '../db';
import { Clock, ShieldAlert, Plus, Users, Search } from 'lucide-react';

interface Props {
  onExtendAccess: (userId: string) => void;
}

const AdminDashboard: React.FC<Props> = ({ onExtendAccess }) => {
  const [users, setUsers] = useState<User[]>([]);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    setUsers(getStoredUsers());
  }, []);

  const refreshList = () => {
    setUsers(getStoredUsers());
  };

  const filteredUsers = users.filter(u => 
    u.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    u.instrument.toLowerCase().includes(searchTerm.toLowerCase()) ||
    u.id.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Admin Control Panel</h2>
          <p className="text-slate-500">Manage member temporary access permissions.</p>
        </div>

        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
          <input 
            type="text" 
            placeholder="Search members..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-lg outline-none focus:ring-2 focus:ring-indigo-500 w-full sm:w-64"
          />
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-200">
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Member</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Instrument</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider">Current Temp Access</th>
                <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-wider text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredUsers.length === 0 ? (
                <tr>
                  <td colSpan={4} className="px-6 py-10 text-center text-slate-400 italic">No members found matching your search.</td>
                </tr>
              ) : (
                filteredUsers.map((user) => (
                  <tr key={user.id} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center font-bold">
                          {user.name.charAt(0)}
                        </div>
                        <div>
                          <p className="font-semibold text-slate-800">{user.name}</p>
                          <p className="text-xs text-slate-400">ID: {user.id}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-slate-100 text-slate-800">
                        {user.instrument}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      {user.temp_access_until ? (
                        <div className="flex items-center gap-2 text-sm">
                          <Clock size={14} className={new Date(user.temp_access_until) > new Date() ? "text-green-500" : "text-slate-300"} />
                          <span className={new Date(user.temp_access_until) > new Date() ? "text-slate-700" : "text-slate-400"}>
                            {new Date(user.temp_access_until).toLocaleString()}
                          </span>
                        </div>
                      ) : (
                        <span className="text-xs text-slate-300">No grant</span>
                      )}
                    </td>
                    <td className="px-6 py-4 text-right">
                      <button 
                        onClick={() => {
                          onExtendAccess(user.id);
                          refreshList();
                        }}
                        className="inline-flex items-center gap-1 bg-indigo-50 hover:bg-indigo-100 text-indigo-600 px-3 py-1.5 rounded-lg text-sm font-semibold transition"
                      >
                        <Plus size={16} />
                        1 Hr Grant
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      <div className="bg-amber-50 border border-amber-100 rounded-xl p-4 flex gap-3">
        <ShieldAlert className="text-amber-500 shrink-0" size={20} />
        <div>
          <p className="text-amber-800 font-semibold text-sm">Administrator Reminder</p>
          <p className="text-amber-700 text-xs">
            Manual grants should only be issued for authorized practice sessions or emergency rehearsals.
            All access logs are recorded for audit purposes.
          </p>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect } from 'react';
import { User, AuthState } from './types';
import { getStoredUsers, saveUsers, isAccessAllowed, getScoreForInstrument } from './db';
import LoginPage from './components/LoginPage';
import MemberDashboard from './components/MemberDashboard';
import AdminDashboard from './components/AdminDashboard';
import { Lock, Music, ShieldCheck, LogOut } from 'lucide-react';

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({ user: null, isAuthenticated: false });
  const [currentPage, setCurrentPage] = useState<'home' | 'scores' | 'admin'>('home');

  // Load session from local storage on mount
  useEffect(() => {
    const savedSession = localStorage.getItem('orchestra_session');
    if (savedSession) {
      setAuth({ user: JSON.parse(savedSession), isAuthenticated: true });
    }
  }, []);

  const handleLogin = (userId: string, pass: string) => {
    // In a real Flask app, this would be a POST request
    const users = getStoredUsers();
    const user = users.find(u => u.id === userId);

    // For mock, any password that matches "1234" or matches userId works
    if (user && (pass === '1234' || pass === userId)) {
      setAuth({ user, isAuthenticated: true });
      localStorage.setItem('orchestra_session', JSON.stringify(user));
    } else {
      alert('Invalid credentials. (Try ID: admin/violin1/cello1 and PW: 1234)');
    }
  };

  const handleLogout = () => {
    setAuth({ user: null, isAuthenticated: false });
    localStorage.removeItem('orchestra_session');
    setCurrentPage('home');
  };

  const extendAccess = (userId: string) => {
    const users = getStoredUsers();
    const updatedUsers = users.map(u => {
      if (u.id === userId) {
        const currentUntil = u.temp_access_until ? new Date(u.temp_access_until) : new Date();
        const base = currentUntil > new Date() ? currentUntil : new Date();
        const newUntil = new Date(base.getTime() + 60 * 60 * 1000); // +1 hour
        return { ...u, temp_access_until: newUntil.toISOString() };
      }
      return u;
    });
    saveUsers(updatedUsers);

    // Update local state if the current user was modified
    if (auth.user?.id === userId) {
      const updatedUser = updatedUsers.find(u => u.id === userId)!;
      setAuth(prev => ({ ...prev, user: updatedUser }));
      localStorage.setItem('orchestra_session', JSON.stringify(updatedUser));
    }

    alert(`Access extended for 1 hour for ${userId}`);
  };

  if (!auth.isAuthenticated || !auth.user) {
    return <LoginPage onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Navigation Header */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between sticky top-0 z-10 shadow-sm">
        <div className="flex items-center gap-2 cursor-pointer" onClick={() => setCurrentPage('home')}>
          <Music className="text-indigo-600 w-8 h-8" />
          <h1 className="text-xl font-bold text-slate-800 hidden sm:block">Score Gateway</h1>
        </div>

        <nav className="flex items-center gap-4">
          <button 
            onClick={() => setCurrentPage('home')}
            className={`px-3 py-2 rounded-md transition ${currentPage === 'home' ? 'bg-indigo-50 text-indigo-700' : 'text-slate-600 hover:bg-slate-100'}`}
          >
            Dashboard
          </button>

          {auth.user.role === 'admin' && (
            <button 
              onClick={() => setCurrentPage('admin')}
              className={`px-3 py-2 rounded-md flex items-center gap-2 transition ${currentPage === 'admin' ? 'bg-indigo-50 text-indigo-700' : 'text-slate-600 hover:bg-slate-100'}`}
            >
              <ShieldCheck size={18} />
              Admin
            </button>
          )}

          <div className="h-6 w-px bg-slate-200 mx-2"></div>

          <div className="flex items-center gap-3">
            <span className="text-sm font-medium text-slate-700 hidden md:block">
              {auth.user.name} ({auth.user.instrument})
            </span>
            <button 
              onClick={handleLogout}
              className="p-2 text-slate-500 hover:text-red-600 hover:bg-red-50 rounded-full transition"
              title="Logout"
            >
              <LogOut size={20} />
            </button>
          </div>
        </nav>
      </header>

      <main className="flex-1 container mx-auto px-4 py-8 max-w-4xl">
        {currentPage === 'home' && (
          <MemberDashboard 
            user={auth.user} 
            onOpenScores={() => setCurrentPage('scores')} 
            onGoToAdmin={() => setCurrentPage('admin')}
          />
        )}

        {currentPage === 'scores' && (
          <ScoreViewer user={auth.user} />
        )}

        {currentPage === 'admin' && auth.user.role === 'admin' && (
          <AdminDashboard onExtendAccess={extendAccess} />
        )}
      </main>

      <footer className="py-6 text-center text-slate-400 text-sm border-t border-slate-100">
        &copy; 2024 Orchestra Digital Library System
      </footer>
    </div>
  );
};

// Internal Helper for Score Logic
const ScoreViewer: React.FC<{ user: User }> = ({ user }) => {
  const { allowed, reason } = isAccessAllowed(user);

  if (!allowed) {
    return (
      <div className="bg-white rounded-2xl shadow-xl p-8 text-center max-w-md mx-auto border border-red-100">
        <div className="bg-red-50 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-6">
          <Lock className="text-red-500 w-8 h-8" />
        </div>
        <h2 className="text-2xl font-bold text-slate-800 mb-2">Access Denied</h2>
        <p className="text-slate-600 mb-6">
