          <div className="p-2 bg-indigo-600 rounded-lg group-hover:rotate-12 transition-transform">
            <Music className="text-white w-5 h-5" />
          </div>
          <h1 className="text-xl font-bold text-slate-800 hidden sm:block">Score Gateway</h1>
        </div>

        <nav className="flex items-center gap-1 sm:gap-4">
          <button 
            onClick={() => setCurrentPage('home')}
            className={`px-3 py-2 rounded-lg flex items-center gap-2 transition font-medium ${currentPage === 'home' ? 'bg-slate-100 text-slate-900 shadow-sm' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <LayoutDashboard size={18} />
            <span className="hidden xs:inline">Dashboard</span>
          </button>

          {auth.user.role === 'admin' && (
            <button 
              onClick={() => setCurrentPage('admin')}
              className={`px-3 py-2 rounded-lg flex items-center gap-2 transition font-bold border-2 ${currentPage === 'admin' ? 'bg-amber-50 border-amber-200 text-amber-700 shadow-sm' : 'border-transparent text-amber-600 hover:bg-amber-50 hover:border-amber-100'}`}
            >
              <ShieldCheck size={18} />
              <span>Admin Page</span>
            </button>
          )}

          <div className="h-6 w-px bg-slate-200 mx-1"></div>

          <div className="flex items-center gap-3 ml-1">
            <div className="hidden md:flex flex-col items-end leading-tight">
              <span className="text-sm font-bold text-slate-700">{auth.user.name}</span>
              <span className="text-[10px] uppercase tracking-wider text-slate-400 font-semibold">{auth.user.instrument}</span>
            </div>
            <button 
              onClick={handleLogout}
              className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition"
              title="Logout"
            >
              <LogOut size={20} />
            </button>
          </div>
        </nav>
      </header>

      <main className="flex-1 container mx-auto px-4 py-8 max-w-4xl">
        {currentPage === 'home' && (
          <MemberDashboard 
            user={auth.user} 
            onOpenScores={() => setCurrentPage('scores')} 
            onGoToAdmin={() => setCurrentPage('admin')}
          />
        )}

        {currentPage === 'scores' && (
          <ScoreViewer user={auth.user} />
        )}

        {currentPage === 'admin' && auth.user.role === 'admin' && (
          <AdminDashboard onExtendAccess={extendAccess} />
        )}
      </main>

      <footer className="py-8 bg-slate-100/50 border-t border-slate-200 mt-auto">
        <div className="container mx-auto px-4 flex flex-col md:flex-row justify-between items-center gap-4 text-slate-400 text-sm">
          <p>&copy; 2024 Orchestra Digital Library System</p>
          <div className="flex gap-6">
            <a href="#" className="hover:text-slate-600 transition">Terms</a>
            <a href="#" className="hover:text-slate-600 transition">Privacy</a>
            {auth.user.role === 'admin' && (
