            <form onSubmit={verifyAdminCode} className="p-8">
              <input 
                autoFocus
                type="password"
                value={adminInput}
                onChange={(e) => {
                  setAdminInput(e.target.value);
                  setAuthError(false);
                }}
                className={`w-full px-4 py-4 bg-slate-50 border-2 rounded-xl text-center text-2xl font-mono tracking-widest outline-none transition ${authError ? 'border-red-500 bg-red-50 animate-shake' : 'border-slate-100 focus:border-indigo-500'}`}
                placeholder="••••••••"
              />
              {authError && <p className="text-red-500 text-xs mt-3 text-center font-bold">ACCESS DENIED: INVALID CODE</p>}

              <div className="flex gap-3 mt-6">
