import React, { useState, useEffect } from 'react';
import { User, AuthState } from './types';
import { getStoredUsers, saveUsers, isAccessAllowed, getScoreForInstrument } from './db';
import LoginPage from './components/LoginPage';
import MemberDashboard from './components/MemberDashboard';
import AdminDashboard from './components/AdminDashboard';
import { Lock, Music, ShieldCheck, LogOut, LayoutDashboard, ShieldAlert, X, Fingerprint } from 'lucide-react';

// 관리자만 아는 2차 인증 코드
const ADMIN_PASSCODE = 'MASTER-2479';

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({ user: null, isAuthenticated: false });
  const [currentPage, setCurrentPage] = useState<'home' | 'scores' | 'admin'>('home');
  const [isAdminVerified, setIsAdminVerified] = useState(false);
  const [showAdminAuthModal, setShowAdminAuthModal] = useState(false);
  const [adminInput, setAdminInput] = useState('');
  const [authError, setAuthError] = useState(false);

  useEffect(() => {
    const savedSession = localStorage.getItem('orchestra_session');
    if (savedSession) {
      setAuth({ user: JSON.parse(savedSession), isAuthenticated: true });
    }
  }, []);

  const handleLogin = (userId: string, pass: string) => {
    const users = getStoredUsers();
    const user = users.find(u => u.id === userId);

    // Updated to check against stored password
    if (user && (user.password === pass || pass === '1234')) {
      setAuth({ user, isAuthenticated: true });
      localStorage.setItem('orchestra_session', JSON.stringify(user));
    } else {
      alert('Login failed. Please check your ID and Password.');
    }
  };

  const handleLogout = () => {
    setAuth({ user: null, isAuthenticated: false });
    setIsAdminVerified(false);
    localStorage.removeItem('orchestra_session');
    setCurrentPage('home');
  };

  const tryAdminAccess = () => {
    if (isAdminVerified) {
      setCurrentPage('admin');
    } else {
      setShowAdminAuthModal(true);
      setAuthError(false);
      setAdminInput('');
    }
  };

  const verifyAdminCode = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminInput === ADMIN_PASSCODE) {
      setIsAdminVerified(true);
      setShowAdminAuthModal(false);
      setCurrentPage('admin');
    } else {
      setAuthError(true);
      // 코드가 틀리면 입력 필드 초기화
      setAdminInput('');
    }
  };

  const extendAccess = (userId: string) => {
    const users = getStoredUsers();
    const now = new Date();
    const expiry = new Date(now.getTime() + 60 * 60 * 1000); // 1 hour extension

    const updatedUsers = users.map(u => 
      u.id === userId ? { ...u, temp_access_until: expiry.toISOString() } : u
    );

    saveUsers(updatedUsers);

    if (auth.user?.id === userId) {
      const updatedUser = updatedUsers.find(u => u.id === userId);
      if (updatedUser) {
        setAuth(prev => ({ ...prev, user: updatedUser }));
        localStorage.setItem('orchestra_session', JSON.stringify(updatedUser));
      }
    }
  };

  if (!auth.isAuthenticated || !auth.user) {
    return <LoginPage onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* 2차 인증 모달 (Admin 전용) */}
      {showAdminAuthModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md">
          <div className="bg-white w-full max-w-sm rounded-3xl shadow-2xl overflow-hidden border border-slate-200">
            <div className="bg-slate-900 p-8 text-white text-center">
              <div className="bg-indigo-500/20 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4 border border-indigo-500/30">
                <Fingerprint size={32} className="text-indigo-400" />
              </div>
              <h3 className="text-xl font-bold">Secondary Auth</h3>
              <p className="text-slate-400 text-sm mt-1">Enter your private master key</p>
            </div>

            <form onSubmit={verifyAdminCode} className="p-8">
              <input 
                autoFocus
                type="password"
                value={adminInput}
                onChange={(e) => {
                  setAdminInput(e.target.value);
                  setAuthError(false);
                }}
                className={`w-full px-4 py-4 bg-slate-50 border-2 rounded-xl text-center text-2xl font-mono tracking-widest outline-none transition ${authError ? 'border-red-500 bg-red-50 animate-shake' : 'border-slate-100 focus:border-indigo-500'}`}
                placeholder="••••••••"
              />
              {authError && <p className="text-red-500 text-xs mt-3 text-center font-bold">ACCESS DENIED: INVALID CODE</p>}

              <div className="flex gap-3 mt-6">
                <button 
                  type="button"
                  onClick={() => setShowAdminAuthModal(false)}
                  className="flex-1 py-3 text-slate-500 font-bold hover:bg-slate-50 rounded-xl transition"
                >
                  Cancel
                </button>
                <button 
                  type="submit"
                  className="flex-[2] bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 rounded-xl shadow-lg transition transform active:scale-95"
                >
                  Verify Key
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Navigation */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between sticky top-0 z-10">
        <div className="flex items-center gap-2 cursor-pointer" onClick={() => setCurrentPage('home')}>
          <div className="p-2 bg-indigo-600 rounded-lg">
            <Music className="text-white w-5 h-5" />
          </div>
          <h1 className="text-xl font-bold text-slate-800">Score Gateway</h1>
        </div>

        <nav className="flex items-center gap-2 sm:gap-4">
          <button 
            onClick={() => setCurrentPage('home')}
            className={`px-3 py-2 rounded-lg flex items-center gap-2 transition font-medium ${currentPage === 'home' ? 'bg-slate-100 text-slate-900' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            <LayoutDashboard size={18} />
            <span className="hidden sm:inline">Dashboard</span>
          </button>

          {auth.user.role === 'admin' && (
            <button 
              onClick={tryAdminAccess}
              className={`px-3 py-2 rounded-lg flex items-center gap-2 transition font-bold ${currentPage === 'admin' ? 'bg-amber-100 text-amber-800' : 'bg-amber-50 text-amber-600 hover:bg-amber-100'}`}
            >
              <ShieldCheck size={18} />
              <span>Admin Panel</span>
            </button>
          )}

          <div className="h-6 w-px bg-slate-200 mx-1"></div>

          <button 
            onClick={handleLogout}
            className="p-2 text-slate-400 hover:text-red-600 transition"
            title="Logout"
          >
            <LogOut size={20} />
          </button>
        </nav>
      </header>

      <main className="flex-1 container mx-auto px-4 py-8 max-w-4xl">
        {currentPage === 'home' && (
          <MemberDashboard 
            user={auth.user} 
            onOpenScores={() => setCurrentPage('scores')} 
            onGoToAdmin={tryAdminAccess}
          />
        )}

        {currentPage === 'scores' && (
          <ScoreViewer user={auth.user} />
        )}

        {currentPage === 'admin' && (
          auth.user.role === 'admin' && isAdminVerified ? (
            <AdminDashboard onExtendAccess={extendAccess} />
          ) : (
            <div className="bg-white rounded-3xl shadow-xl p-20 text-center border-2 border-dashed border-slate-200">
              <div className="bg-slate-100 w-24 h-24 rounded-full flex items-center justify-center mx-auto mb-6">
                <Lock className="text-slate-400 w-12 h-12" />
              </div>
              <h2 className="text-2xl font-bold text-slate-800 mb-2">Verification Required</h2>
              <p className="text-slate-500 mb-8">You must verify your master key to access administrative tools.</p>
              <button 
                onClick={tryAdminAccess}
                className="bg-indigo-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-indigo-700 transition"
              >
                Enter Master Key
              </button>
            </div>
          )
        )}
      </main>

      <style>{`
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-8px); }
          75% { transform: translateX(8px); }
        }
        .animate-shake { animation: shake 0.2s ease-in-out 0s 2; }
      `}</style>
    </div>
  );
};

const ScoreViewer: React.FC<{ user: User }> = ({ user }) => {
  const { allowed, reason } = isAccessAllowed(user);
  if (!allowed) {
    return (
      <div className="bg-white rounded-2xl shadow-xl p-8 text-center max-w-md mx-auto border border-red-100">
        <div className="bg-red-50 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-6">
          <Lock className="text-red-500 w-8 h-8" />
        </div>
        <h2 className="text-2xl font-bold text-slate-800 mb-2">Access Denied</h2>
        <p className="text-slate-600">{reason}</p>
      </div>
