export interface User {
  id: string;
  name: string;
  password?: string;
  instrument: Instrument;
  role: 'member' | 'admin';
  temp_access_until: string | null; // ISO string
  joined_at?: string; // ISO string
}

export interface Score {
  instrument: Instrument;
  notion_url: string;
}

export interface AuthState {
  user: User | null;
  isAuthenticated: boolean;
}

import { User, Score, Instrument } from './types';

const INITIAL_USERS: User[] = [
  { id: 'admin', name: 'Admin User', password: 'admin-password', instrument: 'Piano', role: 'admin', temp_access_until: null, joined_at: new Date('2024-01-01').toISOString() },
  { id: 'violin1', name: 'Kim Violin', password: '1234', instrument: 'Violin', role: 'member', temp_access_until: null, joined_at: new Date('2024-02-15').toISOString() },
  { id: 'cello1', name: 'Lee Cello', password: '1234', instrument: 'Cello', role: 'member', temp_access_until: null, joined_at: new Date('2024-03-10').toISOString() },
];

export const INSTRUMENTS: Instrument[] = [
  'Violin', 'Viola', 'Cello', 'Double Bass', 
  'Flute', 'Oboe', 'Clarinet', 'Bassoon', 
  'Horn', 'Trumpet', 'Trombone', 'Tuba', 
  'Percussion', 'Piano'
];

const INITIAL_SCORES: Score[] = INSTRUMENTS.map(inst => ({
  instrument: inst,
  notion_url: `https://notion.so/orchestra/${inst.toLowerCase().replace(' ', '-')}-scores`
}));

const USERS_KEY = 'orchestra_gateway_users';
const SCORES_KEY = 'orchestra_gateway_scores';

export const getStoredUsers = (): User[] => {
  const stored = localStorage.getItem(USERS_KEY);
  return stored ? JSON.parse(stored) : INITIAL_USERS;
};

export const saveUsers = (users: User[]) => {
  localStorage.setItem(USERS_KEY, JSON.stringify(users));
};

export const getStoredScores = (): Score[] => {
  const stored = localStorage.getItem(SCORES_KEY);
  return stored ? JSON.parse(stored) : INITIAL_SCORES;
};

export const saveScores = (scores: Score[]) => {
  localStorage.setItem(SCORES_KEY, JSON.stringify(scores));
};

export const registerUser = (userData: Omit<User, 'role' | 'temp_access_until' | 'joined_at'>): { success: boolean; message: string } => {
  const users = getStoredUsers();
  if (users.some(u => u.id === userData.id)) return { success: false, message: 'ID already exists.' };
  const newUser: User = { 
    ...userData, 
    role: 'member', 
    temp_access_until: null,
    joined_at: new Date().toISOString()
  };
  saveUsers([...users, newUser]);
  return { success: true, message: 'Registration successful!' };
};

export const updateUser = (userId: string, updates: Partial<User>) => {
  const users = getStoredUsers();
  const updated = users.map(u => u.id === userId ? { ...u, ...updates } : u);
  saveUsers(updated);
};

export const deleteUser = (userId: string): boolean => {
  const users = getStoredUsers();
  const filtered = users.filter(u => u.id !== userId);
  if (filtered.length === users.length) return false;
  saveUsers(filtered);
  return true;
};

export const isAccessAllowed = (user: User): { allowed: boolean; reason?: string } => {
  const now = new Date();
  const isTuesday = now.getDay() === 2;
  const hour = now.getHours();
  if (isTuesday && hour >= 18 && hour < 23) return { allowed: true, reason: 'Regular Rehearsal' };
  if (user.temp_access_until && new Date(user.temp_access_until) > now) return { allowed: true, reason: 'Temp Access' };
  if (user.role === 'admin') return { allowed: true, reason: 'Admin Privilege' };
  return { allowed: false, reason: 'Locked' };
};

