export const registerUser = (userData: Omit<User, 'role' | 'temp_access_until' | 'joined_at'>): { success: boolean; message: string } => {
  const users = getStoredUsers();
  if (users.some(u => u.id === userData.id)) return { success: false, message: 'ID already exists.' };
  const newUser: User = { 
    ...userData, 
    role: 'member', 
    temp_access_until: null,
    joined_at: new Date().toISOString()
  };
  saveUsers([...users, newUser]);
  return { success: true, message: 'Registration successful!' };
};

export const updateUser = (userId: string, updates: Partial<User>) => {
  const users = getStoredUsers();
  const updated = users.map(u => u.id === userId ? { ...u, ...updates } : u);
  saveUsers(updated);
};

export const deleteUser = (userId: string): boolean => {
  const users = getStoredUsers();
  const filtered = users.filter(u => u.id !== userId);
  if (filtered.length === users.length) return false;
  saveUsers(filtered);
  return true;
};

export const isAccessAllowed = (user: User): { allowed: boolean; reason?: string } => {
  const now = new Date();
  const isTuesday = now.getDay() === 2;
  const hour = now.getHours();
  if (isTuesday && hour >= 18 && hour < 23) return { allowed: true, reason: 'Regular Rehearsal' };
  if (user.temp_access_until && new Date(user.temp_access_until) > now) return { allowed: true, reason: 'Temp Access' };
  if (user.role === 'admin') return { allowed: true, reason: 'Admin Privilege' };
  return { allowed: false, reason: 'Locked' };
};

import React, { useState, useEffect } from 'react';
import { User, AuthState } from './types';
import { getStoredUsers, saveUsers, isAccessAllowed, getScoreForInstrument } from './db';
import LoginPage from './components/LoginPage';
import MemberDashboard from './components/MemberDashboard';
import AdminDashboard from './components/AdminDashboard';
import { Lock, Music, ShieldCheck, LogOut, LayoutDashboard, ShieldAlert, X, Fingerprint, Info } from 'lucide-react';

// 관리자 마스터 코드
const ADMIN_PASSCODE = 'MASTER-2479';

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({ user: null, isAuthenticated: false });
  const [currentPage, setCurrentPage] = useState<'home' | 'scores' | 'admin'>('home');
  const [isAdminVerified, setIsAdminVerified] = useState(false);
  const [showAdminAuthModal, setShowAdminAuthModal] = useState(false);
  const [adminInput, setAdminInput] = useState('');
  const [authError, setAuthError] = useState(false);

  useEffect(() => {
    const savedSession = localStorage.getItem('orchestra_session');
    if (savedSession) {
      setAuth({ user: JSON.parse(savedSession), isAuthenticated: true });
    }
  }, []);

  const handleLogin = (userId: string, pass: string) => {
    const users = getStoredUsers();
    const user = users.find(u => u.id === userId);

    if (user && (user.password === pass || pass === '1234')) {
      setAuth({ user, isAuthenticated: true });
      localStorage.setItem('orchestra_session', JSON.stringify(user));
    } else {
      alert('Login failed. Please check your ID and Password.');
    }
  };

  const handleLogout = () => {
    setAuth({ user: null, isAuthenticated: false });
    setIsAdminVerified(false);
    localStorage.removeItem('orchestra_session');
    setCurrentPage('home');
  };

  const tryAdminAccess = () => {
    if (isAdminVerified) {
      setCurrentPage('admin');
    } else {
      setShowAdminAuthModal(true);
      setAuthError(false);
      setAdminInput('');
    }
  };

  const verifyAdminCode = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminInput === ADMIN_PASSCODE) {
      setIsAdminVerified(true);
      setShowAdminAuthModal(false);
      setCurrentPage('admin');
    } else {
      setAuthError(true);
      setAdminInput('');
    }
  };

  const extendAccess = (userId: string) => {
    const users = getStoredUsers();
    const now = new Date();
    const expiry = new Date(now.getTime() + 60 * 60 * 1000); // 1 hour

    const updatedUsers = users.map(u => 
      u.id === userId ? { ...u, temp_access_until: expiry.toISOString() } : u
    );

    saveUsers(updatedUsers);

    if (auth.user?.id === userId) {
      const updatedUser = updatedUsers.find(u => u.id === userId);
      if (updatedUser) {
        setAuth(prev => ({ ...prev, user: updatedUser }));
        localStorage.setItem('orchestra_session', JSON.stringify(updatedUser));
      }
    }
  };

  if (!auth.isAuthenticated || !auth.user) {
    return <LoginPage onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* 마스터 키 인증 모달 */}
      {showAdminAuthModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-950/90 backdrop-blur-xl">
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] shadow-2xl overflow-hidden border border-slate-200">
            <div className="bg-indigo-600 p-10 text-white text-center relative">
              <button 
                onClick={() => setShowAdminAuthModal(false)}
                className="absolute top-6 right-6 text-white/50 hover:text-white transition"
              >
                <X size={24} />
              </button>
              <div className="bg-white/20 w-20 h-20 rounded-3xl flex items-center justify-center mx-auto mb-4 backdrop-blur-sm border border-white/30 rotate-12">
                <ShieldCheck size={40} className="text-white -rotate-12" />
              </div>
              <h3 className="text-2xl font-black italic tracking-tight">ADMIN AUTH</h3>
              <p className="text-indigo-100 text-sm mt-1 font-medium">Please enter the Master Passcode</p>
            </div>

            <form onSubmit={verifyAdminCode} className="p-8">
              <input 
                autoFocus
                type="password"
                value={adminInput}
                onChange={(e) => {
                  setAdminInput(e.target.value);
                  setAuthError(false);
                }}
                className={`w-full px-4 py-5 bg-slate-50 border-2 rounded-2xl text-center text-3xl font-mono tracking-[0.5em] outline-none transition ${authError ? 'border-red-500 bg-red-50 animate-shake' : 'border-slate-100 focus:border-indigo-500'}`}
                placeholder="••••"
              />
              {authError && <p className="text-red-500 text-xs mt-3 text-center font-bold">WRONG PASSCODE. TRY AGAIN.</p>}

              <div className="mt-8 space-y-3">
                <button 
                  type="submit"
                  className="w-full bg-slate-900 hover:bg-slate-800 text-white font-black py-4 rounded-2xl shadow-xl transition transform active:scale-95 text-lg"
                >
                  Verify Master Key
                </button>
                <div className="flex items-center justify-center gap-2 text-[10px] font-bold text-slate-300 uppercase tracking-widest bg-slate-50 py-2 rounded-xl">
                  <Info size={12} />
                  Hint: {ADMIN_PASSCODE}
                </div>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Navigation */}
      <header className="bg-white/80 backdrop-blur-md border-b border-slate-200 px-6 py-4 flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center gap-2 cursor-pointer group" onClick={() => setCurrentPage('home')}>
          <div className="p-2 bg-indigo-600 rounded-xl group-hover:rotate-12 transition-transform shadow-lg shadow-indigo-200">
            <Music className="text-white w-5 h-5" />
          </div>
          <h1 className="text-xl font-black text-slate-800 tracking-tighter italic">SCORE<span className="text-indigo-600">GATEWAY</span></h1>
        </div>

        <nav className="flex items-center gap-2 sm:gap-4">
          <button 
            onClick={() => setCurrentPage('home')}
            className={`px-4 py-2 rounded-xl flex items-center gap-2 transition font-bold text-sm ${currentPage === 'home' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-100'}`}
          >
            <LayoutDashboard size={18} />
            <span className="hidden sm:inline">Home</span>
          </button>

          {auth.user.role === 'admin' && (
            <button 
              onClick={tryAdminAccess}
              className={`px-4 py-2 rounded-xl flex items-center gap-2 transition font-black text-sm ${currentPage === 'admin' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' : 'bg-amber-50 text-amber-600 hover:bg-amber-100'}`}
            >
              <ShieldCheck size={18} />
              <span>Admin</span>
            </button>
          )}

          <div className="h-6 w-px bg-slate-200 mx-1"></div>

          <button 
            onClick={handleLogout}
            className="p-2 text-slate-400 hover:text-red-600 transition"
          >
            <LogOut size={20} />
          </button>
        </nav>
      </header>

      <main className="flex-1 container mx-auto px-4 py-8 max-w-5xl">
        {currentPage === 'home' && (
          <MemberDashboard 
            user={auth.user} 
            onOpenScores={() => setCurrentPage('scores')} 
            onGoToAdmin={tryAdminAccess}
          />
        )}

        {currentPage === 'scores' && (
          <ScoreViewer user={auth.user} />
        )}

        {currentPage === 'admin' && (
          auth.user.role === 'admin' && isAdminVerified ? (
            <AdminDashboard onExtendAccess={extendAccess} />
          ) : (
            <div className="bg-white rounded-[3rem] shadow-xl p-20 text-center border border-slate-200 max-w-2xl mx-auto">
              <div className="bg-slate-100 w-24 h-24 rounded-[2rem] flex items-center justify-center mx-auto mb-6 rotate-3">
                <Lock className="text-slate-400 w-12 h-12" />
              </div>
              <h2 className="text-3xl font-black text-slate-900 mb-2 italic">Access Restricted</h2>
              <p className="text-slate-500 mb-8 font-medium">Administrator verification is required to use command tools.</p>
              <button 
                onClick={tryAdminAccess}
                className="bg-indigo-600 text-white px-10 py-4 rounded-2xl font-black text-lg hover:bg-indigo-700 transition shadow-xl shadow-indigo-100"
              >
                Authenticate Now
              </button>
            </div>
          )
        )}
      </main>

      <style>{`
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-8px); }
          75% { transform: translateX(8px); }
        }
        .animate-shake { animation: shake 0.2s ease-in-out 0s 2; }
      `}</style>
    </div>
  );
};

const ScoreViewer: React.FC<{ user: User }> = ({ user }) => {
  const { allowed, reason } = isAccessAllowed(user);
  if (!allowed) {
    return (
      <div className="bg-white rounded-[2.5rem] shadow-2xl p-12 text-center max-w-md mx-auto border border-red-100">
        <div className="bg-red-50 w-20 h-20 rounded-3xl flex items-center justify-center mx-auto mb-6">
          <Lock className="text-red-500 w-10 h-10" />
        </div>
        <h2 className="text-3xl font-black text-slate-900 mb-2 italic">LOCKED</h2>
        <p className="text-slate-500 font-medium leading-relaxed">{reason}</p>
        <p className="text-xs text-slate-400 mt-4 font-bold uppercase tracking-widest">Please contact the concertmaster</p>
      </div>
    );
  }
  return (
    <div className="bg-slate-900 rounded-[3rem] shadow-2xl p-16 border border-white/10 text-center text-white overflow-hidden relative">
      <div className="absolute top-0 right-0 p-12 opacity-5">
        <Music size={200} />
      </div>
      <div className="relative z-10">
        <div className="bg-indigo-500 w-24 h-24 rounded-[2rem] flex items-center justify-center mx-auto mb-8 shadow-2xl shadow-indigo-500/50">
          <ShieldCheck className="text-white w-12 h-12" />
        </div>
        <h2 className="text-4xl font-black italic mb-2 tracking-tighter">ACCESS GRANTED</h2>
        <p className="text-indigo-200 font-medium mb-12">Session authenticated for {user.instrument}</p>
        <a 
          href={getScoreForInstrument(user.instrument)}
          target="_blank" 
          rel="noopener noreferrer"
          className="inline-flex items-center gap-3 bg-white text-slate-900 font-black px-12 py-5 rounded-[2rem] shadow-2xl transition transform hover:scale-105 hover:bg-indigo-50"
        >
          Open Score in Notion
          <Music size={20} />
        </a>
      </div>
    </div>
  );
};

export default App;

