  onLogin: (id: string, pass: string) => void;
}

const instrumentTranslation: Record<string, string> = {
  'Violin': '바이올린', 'Viola': '비올라', 'Cello': '첼로', 'Double Bass': '더블베이스',
  'Flute': '플루트', 'Oboe': '오보에', 'Clarinet': '클라리넷', 'Bassoon': '바순',
  'Horn': '호른', 'Trumpet': '트럼펫', 'Trombone': '트롬본', 'Tuba': '튜바',
  'Percussion': '타악기', 'Piano': '피아노'
};

const LoginPage: React.FC<Props> = ({ onLogin }) => {
  const [view, setView] = useState<'login' | 'signup'>('login');

  // Login State
  const [userId, setUserId] = useState('');
  const [password, setPassword] = useState('');

  // Signup State
  const [newId, setNewId] = useState('');
  const [newName, setNewName] = useState('');
  const [newInstrument, setNewInstrument] = useState<Instrument>('Violin');
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  const handleLoginSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onLogin(userId, password);
  };

  const handleSignupSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newPassword !== confirmPassword) {
      alert('비밀번호가 일치하지 않습니다.');
      return;
    }

    const result = registerUser({
      id: newId,
      name: newName,
      password: newPassword,
      instrument: newInstrument
    });

    if (result.success) {
      alert('등록이 완료되었습니다! 이제 로그인할 수 있습니다.');
      setView('login');
      setUserId(newId);
    } else {
      alert(result.message);
    }
  };

  return (
    <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
      <div className="w-full max-w-md bg-white rounded-3xl shadow-2xl overflow-hidden transition-all duration-500">
        {/* Header Section */}
        <div className="bg-indigo-600 p-8 text-center relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-full opacity-10 pointer-events-none">
            <div className="absolute -top-10 -left-10 w-40 h-40 bg-white rounded-full"></div>
            <div className="absolute -bottom-10 -right-10 w-40 h-40 bg-white rounded-full"></div>
          </div>
          <div className="inline-flex items-center justify-center w-16 h-16 bg-white/20 backdrop-blur-md rounded-2xl mb-3 relative z-10">
            <Music className="text-white w-8 h-8" />
          </div>
          <h1 className="text-2xl font-bold text-white mb-1 relative z-10">악보 게이트웨이</h1>
          <p className="text-indigo-100 text-xs opacity-80 relative z-10">
            {view === 'login' ? '단원 전용 보안 접속' : '신입 단원 등록'}
          </p>
        </div>

        <div className="p-8">
          {view === 'login' ? (
            <form onSubmit={handleLoginSubmit} className="space-y-5">
              <div>
                <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-2">단원 ID</label>
                <div className="relative">
                  <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400">
                    <UserIcon size={18} />
                  </span>
                  <input 
                    type="text" 
                    value={userId}
                    onChange={(e) => setUserId(e.target.value)}
                    className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition"
                    placeholder="아이디를 입력하세요"
                    required
                  />
                </div>
              </div>

              <div>
                <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-2">비밀번호</label>
                <div className="relative">
                  <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400">
                    <Lock size={18} />
                  </span>
                  <input 
                    type="password" 
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition"
                    placeholder="••••••••"
                    required
                  />
                </div>
              </div>

              <button 
                type="submit"
                className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-4 rounded-xl shadow-lg transition transform active:scale-95"
              >
                로그인
              </button>

              <div className="pt-6 border-t border-slate-100 text-center">
                <button 
                  type="button"
                  onClick={() => setView('signup')}
                  className="inline-flex items-center gap-2 text-indigo-600 font-bold hover:text-indigo-800 transition text-sm"
                >
                  <UserPlus size={16} />
                  계정이 없으신가요? 회원가입
                </button>
              </div>
            </form>
          ) : (
            <form onSubmit={handleSignupSubmit} className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-2">이름</label>
                  <input 
                    type="text" 
                    value={newName}
                    onChange={(e) => setNewName(e.target.value)}
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                    placeholder="홍길동"
                    required
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-2">ID</label>
                  <input 
                    type="text" 
                    value={newId}
                    onChange={(e) => setNewId(e.target.value)}
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                    placeholder="아이디"
                    required
                  />
                </div>
              </div>

              <div>
                <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-2">악기</label>
                <div className="relative">
                  <select 
                    value={newInstrument}
                    onChange={(e) => setNewInstrument(e.target.value as Instrument)}
                    className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none appearance-none"
                  >
                    {INSTRUMENTS.map(inst => (
                      <option key={inst} value={inst}>{instrumentTranslation[inst]}</option>
                    ))}
                  </select>
                  <ChevronDown size={18} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" />
                </div>
              </div>

              <div>
                <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-2">비밀번호</label>
                <input 
                  type="password" 
                  value={newPassword}
                  onChange={(e) => setNewPassword(e.target.value)}
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                  placeholder="최소 4자 이상"
                  required
                />
              </div>

              <div>
                <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-2">비밀번호 확인</label>
                <input 
                  type="password" 
                  value={confirmPassword}
                  onChange={(e) => setConfirmPassword(e.target.value)}
                  className="w-full px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                  placeholder="다시 입력하세요"
                  required
                />
              </div>

              <button 
                type="submit"
                className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-4 rounded-xl shadow-lg transition transform active:scale-95 mt-2"
              >
                계정 생성
              </button>

              <button 
                type="button"
                onClick={() => setView('login')}
                className="w-full inline-flex items-center justify-center gap-2 text-slate-400 font-bold hover:text-slate-600 transition text-sm py-2"
              >
                <ArrowLeft size={16} />
                로그인으로 돌아가기
              </button>
            </form>
          )}
        </div>
      </div>
    </div>
  );
};

export default LoginPage;

import React, { useState, useEffect } from 'react';
import { User, Instrument, Score } from '../types';
import { getStoredUsers, deleteUser, updateUser, INSTRUMENTS, getStoredScores, saveScores, isAccessAllowed } from '../db';
import { 
  Users, Search, Trash2, UserPlus, ShieldCheck, 
  FileText, Save, Clock, XCircle, MoreVertical,
  Filter, Download, ArrowUpDown, ChevronRight, Activity,
  Server, UserCheck, ShieldAlert
} from 'lucide-react';

interface Props {
  onExtendAccess: (userId: string) => void;
}

const instrumentTranslation: Record<string, string> = {
  'Violin': '바이올린', 'Viola': '비올라', 'Cello': '첼로', 'Double Bass': '더블베이스',
  'Flute': '플루트', 'Oboe': '오보에', 'Clarinet': '클라리넷', 'Bassoon': '바순',
  'Horn': '호른', 'Trumpet': '트럼펫', 'Trombone': '트롬본', 'Tuba': '튜바',
  'Percussion': '타악기', 'Piano': '피아노'
};

const AdminDashboard: React.FC<Props> = ({ onExtendAccess }) => {
  const [users, setUsers] = useState<User[]>([]);
  const [scores, setScores] = useState<Score[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterInstrument, setFilterInstrument] = useState<string>('All');
  const [showAddMember, setShowAddMember] = useState(false);

  const [newMember, setNewMember] = useState({ id: '', name: '', instrument: 'Violin' as Instrument, password: '1234' });

  useEffect(() => {
    loadData();
  }, []);

  const loadData = () => {
    setUsers(getStoredUsers());
    setScores(getStoredScores());
  };

  const handleToggleRole = (user: User) => {
    if (user.id === 'admin') return;
    updateUser(user.id, { role: user.role === 'admin' ? 'member' : 'admin' });
    loadData();
  };

  const handleRevokeAccess = (userId: string) => {
    updateUser(userId, { temp_access_until: null });
    loadData();
  };

  const handleAddMember = (e: React.FormEvent) => {
    e.preventDefault();
    const currentUsers = getStoredUsers();
    if (currentUsers.some(u => u.id === newMember.id)) {
      alert('이미 존재하는 ID입니다.');
      return;
    }
    const newUser: User = { 
      ...newMember, 
      role: 'member', 
      temp_access_until: null, 
      joined_at: new Date().toISOString() 
    };
    const updated = [...currentUsers, newUser];
    localStorage.setItem('orchestra_gateway_users', JSON.stringify(updated));
    loadData();
    setShowAddMember(false);
    setNewMember({ id: '', name: '', instrument: 'Violin', password: '1234' });
  };

  const filteredUsers = users.filter(u => {
    const matchesSearch = u.name.toLowerCase().includes(searchTerm.toLowerCase()) || u.id.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesInst = filterInstrument === 'All' || u.instrument === filterInstrument;
    return matchesSearch && matchesInst;
  });

  // Stats
  const activeAccessCount = users.filter(u => isAccessAllowed(u).allowed).length;

  return (
    <div className="space-y-8 pb-32">
      {/* System Summary Widgets */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-slate-900 rounded-[2rem] p-6 text-white border border-white/5 flex items-center gap-5 shadow-2xl">
          <div className="bg-indigo-500/20 p-4 rounded-3xl">
            <Users className="text-indigo-400" size={32} />
          </div>
          <div>
            <p className="text-xs font-black text-slate-500 uppercase tracking-widest">총 단원 수</p>
            <p className="text-3xl font-black">{users.length}</p>
          </div>
        </div>
        <div className="bg-slate-900 rounded-[2rem] p-6 text-white border border-white/5 flex items-center gap-5 shadow-2xl">
          <div className="bg-green-500/20 p-4 rounded-3xl">
            <UserCheck className="text-green-400" size={32} />
          </div>
          <div>
            <p className="text-xs font-black text-slate-500 uppercase tracking-widest">현재 접속 권한</p>
            <p className="text-3xl font-black">{activeAccessCount}</p>
          </div>
        </div>
        <div className="bg-slate-900 rounded-[2rem] p-6 text-white border border-white/5 flex items-center gap-5 shadow-2xl">
          <div className="bg-amber-500/20 p-4 rounded-3xl">
            <Server className="text-amber-400" size={32} />
          </div>
          <div>
            <p className="text-xs font-black text-slate-500 uppercase tracking-widest">시스템 상태</p>
            <p className="text-3xl font-black">정상</p>
          </div>
        </div>
      </div>

      {/* Main Control Panel */}
      <div className="bg-slate-950 rounded-[3rem] p-10 text-white shadow-3xl border border-white/5 overflow-hidden relative">
        <div className="absolute top-0 right-0 w-96 h-96 bg-indigo-500/10 rounded-full -mr-32 -mt-32 blur-[100px]"></div>

        <div className="relative z-10">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 mb-12">
            <div>
              <div className="flex items-center gap-2 text-indigo-400 mb-2">
                <Activity size={18} className="animate-pulse" />
                <span className="text-[10px] font-black uppercase tracking-[0.3em]">Command Center v2.0</span>
              </div>
              <h2 className="text-4xl font-black italic tracking-tighter text-white">단원 명단 관리</h2>
              <p className="text-slate-500 text-sm mt-1 font-medium italic">악단 데이터 및 실시간 출입 권한을 제어합니다.</p>
            </div>

            <button 
              onClick={() => setShowAddMember(!showAddMember)}
              className="bg-indigo-600 hover:bg-indigo-500 text-white px-8 py-4 rounded-[2rem] font-black flex items-center gap-2 transition shadow-2xl shadow-indigo-500/20"
            >
              <UserPlus size={20} />
              신입 단원 등록
            </button>
          </div>

          {/* New Member Registration Inline Form */}
          {showAddMember && (
            <form onSubmit={handleAddMember} className="mb-12 grid grid-cols-1 sm:grid-cols-4 gap-4 p-8 bg-white/5 rounded-[2.5rem] border border-white/10 animate-in slide-in-from-top-4 duration-500">
              <input 
                placeholder="이름" 
                className="bg-slate-900 border border-white/10 rounded-2xl px-5 py-4 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                value={newMember.name}
                onChange={e => setNewMember({...newMember, name: e.target.value})}
                required
              />
              <input 
                placeholder="아이디" 
                className="bg-slate-900 border border-white/10 rounded-2xl px-5 py-4 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                value={newMember.id}
                onChange={e => setNewMember({...newMember, id: e.target.value})}
                required
              />
              <select 
                className="bg-slate-900 border border-white/10 rounded-2xl px-5 py-4 text-sm focus:ring-2 focus:ring-indigo-500 outline-none appearance-none text-white"
                value={newMember.instrument}
                onChange={e => setNewMember({...newMember, instrument: e.target.value as Instrument})}
              >
                {INSTRUMENTS.map(i => <option key={i} value={i} className="bg-slate-900">{instrumentTranslation[i]}</option>)}
              </select>
              <button type="submit" className="bg-white text-slate-950 font-black rounded-2xl hover:bg-slate-100 transition shadow-xl">등록 완료</button>
            </form>
          )}

          {/* Table Filters */}
          <div className="flex flex-col md:flex-row gap-4 mb-8">
            <div className="relative flex-1">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-600" size={18} />
              <input 
                type="text" 
                placeholder="단원 검색 (이름 또는 ID)"
                className="w-full pl-12 pr-6 py-4 bg-white/5 border border-white/5 rounded-2xl text-sm focus:bg-white/10 focus:border-indigo-500 outline-none transition text-white"
                value={searchTerm}
                onChange={e => setSearchTerm(e.target.value)}
              />
            </div>
            <select 
              className="px-6 py-4 bg-white/5 border border-white/5 rounded-2xl text-sm outline-none cursor-pointer hover:bg-white/10 transition text-white"
              value={filterInstrument}
              onChange={e => setFilterInstrument(e.target.value)}
            >
              <option value="All" className="bg-slate-900 text-white">모든 파트</option>
              {INSTRUMENTS.map(i => <option key={i} value={i} className="bg-slate-900 text-white">{instrumentTranslation[i]}</option>)}
            </select>
          </div>

          {/* Master Table */}
          <div className="overflow-x-auto rounded-[2rem] border border-white/5">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-white/5 text-white">
                  <th className="px-8 py-5 text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">신원 확인</th>
                  <th className="px-8 py-5 text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">악기 / 역할</th>
                  <th className="px-8 py-5 text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">상태</th>
                  <th className="px-8 py-5 text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] text-right">작업</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-white/5">
                {filteredUsers.map(user => {
                  const { allowed } = isAccessAllowed(user);
                  return (
                    <tr key={user.id} className="hover:bg-white/[0.02] transition-colors group">
                      <td className="px-8 py-6">
                        <div className="flex items-center gap-4">
                          <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black text-lg ${user.role === 'admin' ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-500'}`}>
                            {user.name.charAt(0)}
                          </div>
                          <div>
                            <p className="font-black text-white leading-none mb-1">{user.name}</p>
                            <p className="text-[10px] font-mono text-slate-600 uppercase tracking-widest">{user.id}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-8 py-6">
                        <div className="flex flex-col gap-1">
                          <span className="text-sm font-bold text-slate-300">{instrumentTranslation[user.instrument] || user.instrument}</span>
                          <button 
                            onClick={() => handleToggleRole(user)}
                            className={`text-[9px] font-black px-2 py-0.5 rounded-lg w-fit uppercase tracking-widest transition-all ${user.role === 'admin' ? 'bg-amber-500/20 text-amber-500' : 'bg-white/10 text-slate-500 hover:bg-white/20 hover:text-white'}`}
                          >
                            {user.role === 'admin' ? '관리자' : '일반 단원'}
                          </button>
                        </div>
                      </td>
                      <td className="px-8 py-6">
                        <div className={`inline-flex items-center gap-2 px-4 py-1.5 rounded-full text-[10px] font-black tracking-widest ${allowed ? 'bg-green-500/10 text-green-400' : 'bg-red-500/10 text-red-400'}`}>
                          <div className={`w-2 h-2 rounded-full ${allowed ? 'bg-green-400 shadow-[0_0_10px_rgba(74,222,128,0.5)] animate-pulse' : 'bg-red-500'}`}></div>
                          {allowed ? '승인됨' : '잠금'}
                        </div>
                      </td>
                      <td className="px-8 py-6 text-right">
                        <div className="flex items-center justify-end gap-3 opacity-30 group-hover:opacity-100 transition-opacity">
                          <button 
                            onClick={() => onExtendAccess(user.id)}
                            className="p-3 bg-indigo-500/10 text-indigo-400 hover:bg-indigo-500 hover:text-white rounded-2xl transition"
                            title="빠른 승인 (1시간)"
                          >
                            <Clock size={18} />
                          </button>
                          <button 
                            onClick={() => handleRevokeAccess(user.id)}
                            className="p-3 bg-amber-500/10 text-amber-400 hover:bg-amber-500 hover:text-white rounded-2xl transition"
                            title="권한 회수"
                          >
                            <XCircle size={18} />
                          </button>
                          <button 
                            disabled={user.id === 'admin'}
                            onClick={() => { if(confirm(`${user.name} 단원을 삭제하시겠습니까?`)) { deleteUser(user.id); loadData(); } }}
                            className="p-3 bg-red-500/10 text-red-400 hover:bg-red-500 hover:text-white rounded-2xl transition disabled:opacity-0"
                          >
                            <Trash2 size={18} />
                          </button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      </div>

      {/* Notion Link Integration */}
      <div className="bg-slate-900 rounded-[3rem] p-12 border border-white/5 text-white">
        <div className="flex items-center justify-between mb-10">
          <div className="flex items-center gap-4">
            <div className="p-4 bg-indigo-600 rounded-3xl shadow-2xl shadow-indigo-500/30">
              <FileText size={24} />
            </div>
            <div>
              <h3 className="text-2xl font-black italic tracking-tighter text-white">악보 자산 관리</h3>
              <p className="text-slate-500 text-sm font-medium">파트별 노션 데이터베이스 URL을 동기화합니다.</p>
            </div>
          </div>
          <button 
            onClick={() => { saveScores(scores); alert('시스템 데이터가 성공적으로 동기화되었습니다.'); }}
            className="flex items-center gap-3 bg-white text-slate-950 px-10 py-4 rounded-2xl font-black hover:bg-indigo-50 transition shadow-xl"
          >
            <Save size={20} />
            모든 데이터 동기화
          </button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {scores.map(s => (
            <div key={s.instrument} className="p-6 bg-white/5 rounded-[2rem] border border-white/5 hover:border-indigo-500/30 transition group">
              <div className="flex justify-between items-center mb-4">
                <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">{instrumentTranslation[s.instrument] || s.instrument} 파트</span>
                <Activity size={14} className="text-indigo-500 opacity-0 group-hover:opacity-100 transition-opacity" />
              </div>
              <input 
                className="w-full bg-slate-950 border border-white/10 rounded-xl px-4 py-3 text-xs font-mono text-indigo-300 focus:ring-2 focus:ring-indigo-500 outline-none transition"
                value={s.notion_url}
                onChange={e => {
                  const updated = scores.map(item => item.instrument === s.instrument ? {...item, notion_url: e.target.value} : item);
                  setScores(updated);
                }}
              />
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
